// Son 24 saatteki haberleri filtrele
const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);

const recentNews = $input.all().filter(item => {
  const pubDate = new Date(item.json.pubDate || item.json.isoDate);
  return pubDate >= yesterday;
});

// Rastgele karıştır (çeşitlilik için)
const shuffled = recentNews.sort(() => Math.random() - 0.5);

// İlk 30 haberi al (Gemini filtrelemesi için)
const topNews = shuffled.slice(0, 30);

return topNews.map(item => ({
  json: {
    title: item.json.title,
    link: item.json.link,
    description: item.json.contentSnippet || item.json.description || '',
    pubDate: item.json.pubDate || item.json.isoDate,
    source: item.json.creator || item.json['dc:creator'] || 'Unknown'
  }
}));

// Tüm haberleri tek bir prompt'a hazırla
const allNews = $input.all();

const newsText = allNews.map((item, index) => {
  return `[${index + 1}]\nKaynak: ${item.json.source}\nBaşlık: ${item.json.title}\nAçıklama: ${item.json.description}\n---`;
}).join('\n\n');

return [{
  json: {
    newsText: newsText,
    allNews: allNews
  }
}];

// Gemini'nin kategorize edilmiş seçimini parse et
const geminiResponse = $input.first().json;

// Gemini response kontrolü
if (!geminiResponse || !geminiResponse.candidates || !geminiResponse.candidates[0]) {
  console.error('Gemini response invalid:', JSON.stringify(geminiResponse));
  return [{
    json: {
      startupNews: [],
      techNews: [],
      energyNews: [],
      totalCount: 0,
      error: 'Gemini API yanıt vermedi'
    }
  }];
}

const responseText = geminiResponse.candidates[0].content.parts[0].text;
console.log('Gemini response:', responseText);

// Kategorileri parse et
const startupMatch = responseText.match(/STARTUP:\s*([\d,\s]+)/i);
const techMatch = responseText.match(/TEKNOLOJİ:\s*([\d,\s]+)/i);
const energyMatch = responseText.match(/ENERJİ:\s*([\d,\s]+)/i);

// Önceki adımdan tüm haberleri al
const allNews = $('Prepare for Gemini').first().json.allNews;

if (!allNews || allNews.length === 0) {
  return [{
    json: {
      startupNews: [],
      techNews: [],
      energyNews: [],
      totalCount: 0,
      error: 'Hiç haber bulunamadı'
    }
  }];
}

const result = {
  startup: [],
  tech: [],
  energy: []
};

if (startupMatch && startupMatch[1]) {
  const startupIndices = startupMatch[1].match(/\d+/g);
  if (startupIndices) {
    result.startup = startupIndices.map(num => parseInt(num) - 1).map(index => allNews[index]).filter(Boolean);
  }
}

if (techMatch && techMatch[1]) {
  const techIndices = techMatch[1].match(/\d+/g);
  if (techIndices) {
    result.tech = techIndices.map(num => parseInt(num) - 1).map(index => allNews[index]).filter(Boolean);
  }
}

if (energyMatch && energyMatch[1]) {
  const energyIndices = energyMatch[1].match(/\d+/g);
  if (energyIndices) {
    result.energy = energyIndices.map(num => parseInt(num) - 1).map(index => allNews[index]).filter(Boolean);
  }
}

return [{
  json: {
    startupNews: result.startup,
    techNews: result.tech,
    energyNews: result.energy,
    totalCount: result.startup.length + result.tech.length + result.energy.length
  }
}];

const data = $input.first().json;
const startupNews = data.startupNews || [];
const techNews = data.techNews || [];
const energyNews = data.energyNews || [];

// HTML email oluştur
