    .empty-category { text-align: center; color: #999; padding: 20px; font-style: italic; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>🚀 Günlük Teknoloji Özeti</h1>
      <p>Teknoloji, Yatırım & Enerji | ${new Date().toLocaleDateString('tr-TR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
    </div>
`;

// STARTUP VE YATIRIM HABERLERİ
emailHTML += `
    <div class="category-header">
      <h2>💰 Startup ve Yatırım Haberleri</h2>
      <span class="count">${startupNews.length} haber</span>
    </div>
`;

if (startupNews.length > 0) {
  startupNews.forEach((item, index) => {
    const preview = item.json.description.substring(0, 200) + (item.json.description.length > 200 ? '...' : '');
    const fullContent = item.json.description;

    emailHTML += `
    <div class="news-item">
      <div class="meta">#${index + 1} • ${item.json.source}</div>
      <h3>${item.json.title}</h3>
