      <details>
        <summary></summary>
        <div class="full-content">${fullContent}</div>
      </details>

      <div class="button-group">
        <a href="${item.json.link}" target="_blank" class="btn btn-secondary">🌐 Siteden Oku →</a>
      </div>
    </div>
    `;
  });
} else {
  emailHTML += '<div class="empty-category">Bugün bu kategoride haber bulunamadı.</div>';
}

// TEKNOLOJİ VE IoT HABERLERİ
emailHTML += `
    <div class="category-header tech">
      <h2>🤖 Teknoloji ve IoT Haberleri</h2>
      <span class="count">${techNews.length} haber</span>
    </div>
`;

if (techNews.length > 0) {
  techNews.forEach((item, index) => {
    const preview = item.json.description.substring(0, 200) + (item.json.description.length > 200 ? '...' : '');
    const fullContent = item.json.description;

    emailHTML += `
    <div class="news-item">
      <div class="meta">#${index + 1} • ${item.json.source}</div>
      <h3>${item.json.title}</h3>
      <p class="preview">${preview}</p>

      <details>
        <summary></summary>
        <div class="full-content">${fullContent}</div>
      </details>

      <div class="button-group">
        <a href="${item.json.link}" target="_blank" class="btn btn-secondary">🌐 Siteden Oku →</a>
      </div>
    </div>
    `;
  });
} else {
  emailHTML += '<div class="empty-category">Bugün bu kategoride haber bulunamadı.</div>';
}

// ENERJİ SEKTÖRÜ HABERLERİ
emailHTML += `
    <div class="category-header energy">
      <h2>⚡ Enerji Sektörü Haberleri</h2>
      <span class="count">${energyNews.length} haber</span>
    </div>
`;

if (energyNews.length > 0) {
  energyNews.forEach((item, index) => {
    const preview = item.json.description.substring(0, 200) + (item.json.description.length > 200 ? '...' : '');
    const fullContent = item.json.description;

    emailHTML += `
    <div class="news-item">
