      <div class="button-group">
        <a href="${item.json.link}" target="_blank" class="btn btn-secondary">🌐 Siteden Oku →</a>
      </div>
    </div>
    `;
  });
} else {
  emailHTML += '<div class="empty-category">Bugün bu kategoride haber bulunamadı.</div>';
}

const totalNews = startupNews.length + techNews.length + energyNews.length;

emailHTML += `
    <div class="footer">
      <p>📊 Toplam ${totalNews} önemli haber seçildi</p>
      <p>💰 ${startupNews.length} Startup • 🤖 ${techNews.length} Teknoloji • ⚡ ${energyNews.length} Enerji</p>
      <p>Bu özet Gemini AI tarafından filtrelenmiştir</p>
